""" STRING """

''' String (str)'''

#Text (Most Common)

name = "Vishal"

#Numbers as Text

number = "12345"

#Special Characters
symbols = "@#$%^&*"

#Mixed Characters
password = "Vishal@123"

#Empty String
empty = ""




""" Tuple """

''' Tuple (tuple)'''

#Tuple of Numbers
numbers = (10, 20, 30, 40)


#Tuple of Strings
states = ("Uttar Pradesh", "Bihar", "Assam", "Gujarat")


#Tuple of Floats
prices = (99.99, 149.50, 250.75)


#Tuple of Booleans
status = (True, False, True)


#Mixed Data Types
student = ("Vishal", 19, 85.5, True)

#Empty Tuple
empty = ()


#Nested Tuple
matrix = ((1, 2), (3, 4), (5, 6))


#Tuple with Duplicate Values
colors = ("Red", "Blue", "Red", "Green")





'''Difference Between List and Tuple'''
""" A list is mutable (changeable), whereas a tuple is immutable (unchangeable)."""



# | List              | Tuple                |
# | ----------------- | -------------------- |
# | **Mutable**       | **Immutable**        |
# | Can add items     | Cannot add items     |
# | Can remove items  | Cannot remove items  |
# | Can replace items | Cannot replace items |
# | Uses `[]`         | Uses `()`            |

'''
Quick Summary

Data Type	Can Store

String (str)	=> Text/characters (letters, digits, symbols)
Tuple (tuple)=>	Numbers, strings, floats, booleans, mixed data types, nested tuples


Easy Memory Trick 🧠


String → Stores text (characters).
List → Stores multiple items (can be changed).
Tuple → Stores multiple items (cannot be changed).'''

